import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import API from '../../services/api';
import { UserPlus, Loader2 } from 'lucide-react';

export default function Register() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: 'reporter' // Default role
  });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await API.post('/auth/register', formData);
      login(data);
      
      // Redirect based on the role they chose
      if (data.role === 'volunteer') navigate('/dashboard');
      else navigate('/report-home');
    } catch (err) {
      alert(err.response?.data?.message || "Registration Failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[90vh] flex items-center justify-center p-6 bg-gray-50">
      <div className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-md">
        <div className="text-center mb-8">
          <div className="bg-green-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <UserPlus className="text-green-600" />
          </div>
          <h1 className="text-2xl font-bold">Join FoodBridge</h1>
          <p className="text-gray-500 text-sm">Create an account to start helping</p>
        </div>

        <form onSubmit={handleRegister} className="space-y-4">
          <input 
            type="text" 
            placeholder="Full Name" 
            className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-green-500"
            onChange={(e) => setFormData({...formData, name: e.target.value})}
            required
          />
          <input 
            type="email" 
            placeholder="Email Address" 
            className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-green-500"
            onChange={(e) => setFormData({...formData, email: e.target.value})}
            required
          />
          <input 
            type="password" 
            placeholder="Password" 
            className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-green-500"
            onChange={(e) => setFormData({...formData, password: e.target.value})}
            required
          />
          
          <div className="flex gap-4 p-1 bg-gray-100 rounded-2xl">
            <button 
              type="button"
              onClick={() => setFormData({...formData, role: 'reporter'})}
              className={`flex-1 py-3 rounded-xl font-bold transition ${formData.role === 'reporter' ? 'bg-white shadow text-green-600' : 'text-gray-500'}`}
            >
              Reporter
            </button>
            <button 
              type="button"
              onClick={() => setFormData({...formData, role: 'volunteer'})}
              className={`flex-1 py-3 rounded-xl font-bold transition ${formData.role === 'volunteer' ? 'bg-white shadow text-green-600' : 'text-gray-500'}`}
            >
              Volunteer
            </button>
          </div>

          <button 
            disabled={loading}
            className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold shadow-lg hover:bg-green-700 transition flex justify-center mt-4"
          >
            {loading ? <Loader2 className="animate-spin" /> : "Create Account"}
          </button>
        </form>

        <p className="text-center mt-6 text-sm text-gray-500">
          Already have an account? <Link to="/login" className="text-green-600 font-bold">Login</Link>
        </p>
      </div>
    </div>
  );
}
